INSERT INTO phrases (id, en, es, level) VALUES
    ('ff6977a6-22a2-581b-8aed-dc250d0870f1', 'Hello, my name is Ana.', 'Hola, me llamo Ana.', 'a1'),
    ('440bca42-ddc1-563b-a3ca-f0344ba0c7b7', 'How are you today?', 'Como estas hoy?', 'a1'),
    ('219f69b2-e6f7-5d0f-93c5-fe465801fa09', 'I would like a glass of water.', 'Me gustaria un vaso de agua.', 'a1'),
    ('c4f3c2a6-9c9c-512d-b26a-e90070219bce', 'Where is the bathroom?', 'Donde esta el bano?', 'a1'),
    ('daa82d37-add9-562b-915c-bce92735a97b', 'I live in a small house.', 'Vivo en una casa pequena.', 'a1'),
    ('a05674a8-e939-5bd8-a4cf-a07f446e8e3e', 'Can you help me, please?', 'Puedes ayudarme, por favor?', 'a1'),
    ('5a315912-162d-5499-93a2-2d88e942d653', 'I have two brothers and one sister.', 'Tengo dos hermanos y una hermana.', 'a1'),
    ('729b51f3-42d5-50bd-9541-5341fe959bd5', 'The weather is nice today.', 'Hace buen tiempo hoy.', 'a1'),
    ('3dba44a8-5875-51ae-b5c9-317153dcc014', 'I like coffee with milk.', 'Me gusta el cafe con leche.', 'a1'),
    ('5477e7d4-1df8-583f-b9be-370215f3c726', 'What time is it?', 'Que hora es?', 'a1'),
    ('ccc79a2c-a69e-5d76-9bcc-7469f9708e86', 'I go to work by bus.', 'Voy al trabajo en autobus.', 'a1'),
    ('fa04bd99-9fca-5fa3-956b-add1bf66ed65', 'This is my friend Carlos.', 'Este es mi amigo Carlos.', 'a1'),
    ('e7ba6e0b-f140-52f5-8562-8e6f61163823', 'I don''t understand.', 'No entiendo.', 'a1'),
    ('ce61768b-9d8a-598b-827a-be18cfb999a8', 'Can you speak slowly, please?', 'Puedes hablar despacio, por favor?', 'a1'),
    ('cb0415f5-1681-58fb-a3ba-822d456f29e1', 'I need to buy some food.', 'Necesito comprar comida.', 'a1'),
    ('3aa40482-71b5-52bf-840b-70d41c682eef', 'I''ve been waiting here for twenty minutes.', 'Llevo esperando aqui veinte minutos.', 'a2'),
    ('f7774562-d090-5271-bf42-f4cc8999a897', 'Could you tell me how to get to the station?', 'Podrias decirme como llegar a la estacion?', 'a2'),
    ('c16cc16c-0273-5ee8-b83a-a632db073e7f', 'I''m looking for a cheaper hotel.', 'Estoy buscando un hotel mas barato.', 'a2'),
    ('a31e23f8-5338-560f-9595-0ff859998f4f', 'What do you usually do on weekends?', 'Que sueles hacer los fines de semana?', 'a2'),
    ('984288dc-d571-5008-b01e-8515f64711fc', 'I''m sorry, I didn''t catch your name.', 'Perdona, no pille tu nombre.', 'a2'),
    ('480a7ffc-f238-556a-8202-a2e69ee7d941', 'The restaurant is next to the bank.', 'El restaurante esta al lado del banco.', 'a2'),
    ('96f4e762-ca09-551b-879f-f1807cfd0b0c', 'I''ve just finished my homework.', 'Acabo de terminar mis deberes.', 'a2'),
    ('2d2bc9a4-1d3f-5089-824e-6cfff7030eb9', 'She''s been learning English for two years.', 'Lleva dos anos aprendiendo ingles.', 'a2'),
    ('db582f2e-3bdd-5f0f-ac2f-0841ad8e6fb0', 'We should leave before it gets dark.', 'Deberiamos irnos antes de que oscurezca.', 'a2'),
    ('7f6c6454-1993-5ffc-b577-eaa71a1c00e7', 'I''d rather stay home than go out.', 'Prefiero quedarme en casa que salir.', 'a2'),
    ('307d8f58-0fd1-5316-9355-1f811a6f14ed', 'Do you mind if I open the window?', 'Te importa si abro la ventana?', 'a2'),
    ('1d42c795-d36a-559a-90bb-0ae0640b2153', 'I''m not sure what to do next.', 'No estoy seguro de que hacer ahora.', 'a2'),
    ('cdac529f-8cd9-5d4d-8bb8-b39473c8b46f', 'The movie was better than I expected.', 'La pelicula fue mejor de lo que esperaba.', 'a2'),
    ('bbaaea1b-b529-5956-9e8a-d81a0a265eec', 'Can I have the bill, please?', 'Me traes la cuenta, por favor?', 'a2'),
    ('62701f32-1618-59b1-ae62-5375f1ad38d6', 'I forgot to bring my umbrella.', 'Olvide traer mi paraguas.', 'a2'),
    ('4d0c03ee-fadb-5696-93ff-92aa7b4c7070', 'If I had more time, I would learn to play the guitar.', 'Si tuviera mas tiempo, aprenderia a tocar la guitarra.', 'b1'),
    ('209ad911-0981-5be7-8e59-5702011972fb', 'I''ve been thinking about changing my job recently.', 'He estado pensando en cambiar de trabajo ultimamente.', 'b1'),
    ('a1d2a8d9-aba2-57dd-8d22-e625dacf263a', 'The book was so interesting that I couldn''t put it down.', 'El libro era tan interesante que no podia dejarlo.', 'b1'),
    ('bb87d4df-6ad2-5087-b04d-eaa121f54031', 'Do you happen to know where the nearest pharmacy is?', 'Sabes donde esta la farmacia mas cercana?', 'b1'),
    ('7275d021-d529-5ab5-bb88-b0aedb5614f4', 'I wish I had studied harder when I was younger.', 'Ojala hubiera estudiado mas cuando era joven.', 'b1'),
    ('fb54cf3e-359b-50a0-ae9e-3cc669fd0171', 'She suggested that we should try the new Italian place.', 'Ella sugirio que probaramos el nuevo sitio italiano.', 'b1'),
    ('71bdd09a-e63d-585e-aacc-317e7b74f4ad', 'It''s been ages since we last saw each other.', 'Hace siglos que no nos vemos.', 'b1'),
    ('a3e668a9-0988-58e8-b5ba-b893c0830ec9', 'I''m not used to getting up so early.', 'No estoy acostumbrado a levantarme tan pronto.', 'b1'),
    ('98be3436-2fed-5a7f-b4ca-98f4a867fe39', 'The traffic was terrible, so I arrived late.', 'El trafico era terrible, asi que llegue tarde.', 'b1'),
    ('d7380658-0541-5cd5-a743-e4de624287d8', 'Would you mind closing the door on your way out?', 'Te importaria cerrar la puerta al salir?', 'b1'),
    ('00b0346b-8274-58bd-8f3f-aa1bf1559d30', 'I''m supposed to meet them at the airport at six.', 'Se supone que los recojo en el aeropuerto a las seis.', 'b1'),
    ('2649472e-1e0c-5bef-a7d0-cf2aff079693', 'He must have forgotten about our meeting.', 'Debe haberse olvidado de nuestra reunion.', 'b1'),
    ('cd706565-1554-5ec9-8801-a27d8b0f5beb', 'The more I practice, the better I get.', 'Cuanto mas practico, mejor me sale.', 'b1'),
    ('fe42a0b4-460c-576e-8fd6-182da1272d40', 'I haven''t made up my mind yet.', 'Aun no me he decidido.', 'b1'),
    ('dd7ca815-1790-564a-8620-96c533d343a9', 'It depends on what time we finish work.', 'Depende de a que hora terminemos de trabajar.', 'b1'),
    ('4e1dec93-e467-5668-b8c6-46571b26588e', 'Had I known about the delay, I would have taken a different route.', 'Si hubiera sabido del retraso, habria tomado otra ruta.', 'b2'),
    ('2534cb9e-206e-568a-86bc-b703b0b77b11', 'She''s the kind of person who always sees the bright side.', 'Es el tipo de persona que siempre ve el lado bueno.', 'b2'),
    ('f256bb65-7a11-568a-bd4d-4e98555e76bc', 'I wouldn''t have bothered if I''d known it was going to be cancelled.', 'No me habria molestado si hubiera sabido que iban a cancelarlo.', 'b2'),
    ('b67b4a24-c31d-5ca5-b23e-d60d169b8d24', 'Not only did he arrive late, but he also forgot the documents.', 'No solo llego tarde, sino que tambien olvido los documentos.', 'b2'),
    ('3b22e166-4140-5b03-8779-2f48aafe60cc', 'The thing is, we can''t afford to make any more mistakes.', 'El tema es que no podemos permitirnos mas errores.', 'b2'),
    ('e9f7b29f-5583-5c8a-8de8-04fa8d37882e', 'It''s about time the government took action on climate change.', 'Ya es hora de que el gobierno actue contra el cambio climatico.', 'b2'),
    ('c23a5551-549b-5090-a936-7fb6227b84e5', 'I''d rather you didn''t mention this to anyone.', 'Preferiria que no le mencionaras esto a nadie.', 'b2'),
    ('0374f506-c7c2-505a-9da9-5a9a2277058b', 'Despite having studied for weeks, I still failed the exam.', 'A pesar de haber estudiado semanas, suspendi el examen.', 'b2'),
    ('f5806392-bbde-5bc1-877f-58b4d8f52378', 'There''s no point in arguing about something we can''t change.', 'No tiene sentido discutir sobre algo que no podemos cambiar.', 'b2'),
    ('d654fb0a-c156-5591-8485-cd29380161f3', 'What struck me most was how calm she remained under pressure.', 'Lo que mas me impresiono fue lo calmada que se mantuvo bajo presion.', 'b2'),
    ('22712eec-8587-58df-95dc-3eea62685f95', 'Had it not been for her timely intervention, the project would have collapsed entirely.', 'De no ser por su intervencion oportuna, el proyecto habria colapsado por completo.', 'c1'),
    ('ae4de75a-e1c6-5791-8955-fed56a36608f', 'She reckons they''ll have sorted it out by the time we get there, but I wouldn''t count on it.', 'Ella cree que lo habran resuelto para cuando lleguemos, pero yo no contaria con ello.', 'c1'),
    ('6e9cf453-7bb9-5180-9c42-ce4f64de0973', 'Under no circumstances should confidential information be disclosed to third parties.', 'Bajo ninguna circunstancia se debe revelar informacion confidencial a terceros.', 'c1'),
    ('77abd873-8da4-50ec-8f6f-77f4b1096ec8', 'The extent to which social media has reshaped public discourse cannot be overstated.', 'No se puede exagerar hasta que punto las redes sociales han transformado el discurso publico.', 'c1'),
    ('9cf96974-552e-5f83-8643-2628a22c08c3', 'It goes without saying that preparation is the cornerstone of any successful negotiation.', 'No hace falta decir que la preparacion es la piedra angular de toda negociacion exitosa.', 'c1'),
    ('f6b10544-f6d2-52d9-be05-bee436319103', 'Notwithstanding the initial setbacks, the team managed to deliver the project on time.', 'A pesar de los contratiempos iniciales, el equipo logro entregar el proyecto a tiempo.', 'c1'),
    ('c3fc76bb-b06a-5071-8089-103da984afcc', 'The findings lend credence to the hypothesis that early intervention yields better outcomes.', 'Los hallazgos dan credibilidad a la hipotesis de que la intervencion temprana da mejores resultados.', 'c1'),
    ('4f462887-29c0-55b0-aa2f-82c45971e7e6', 'I can''t help but wonder whether we''ve been approaching this problem from the wrong angle.', 'No puedo evitar preguntarme si hemos estado abordando este problema desde el angulo equivocado.', 'c1');